class Solution(object):
    def thousandSeparator(self, n):
        s = str(n)
        result = []
        for i, c in enumerate(reversed(s)):
            if i > 0 and i % 3 == 0:
                result.append('.')
            result.append(c)
        return ''.join(reversed(result))
